class Solution {
public:
    string crackSafe(int n, int k) {
        string res;
        for (int i = 0; i < n; i++) res += '0';
        dfs(res, 0, k, n);
        res += '0';
        return res;
    }
    void dfs(string path, int start, int k, int n) {
        for (int i = 0; i < k; i++) {
            string next = path + std::to_string(i);
            if (next.length() == n * (k + 1)) return;
            if (start + i == k) dfs(next, i, k, n);
            else dfs(next, (start + i) % k, k, n);
        }
    }
};
```

efficiency: HIGH
time complexity: O(k^(n * (k + 1)))
space complexity: O(n * (k + 1))
